DROP TABLE IF EXISTS `attendance_record`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `attendance_record` (
  `record_id` bigint NOT NULL AUTO_INCREMENT,
  `user_name` varchar(100) NOT NULL COMMENT '用户名',
  `external_user_id` varchar(100) DEFAULT '' COMMENT '外部系统用户ID',
  `dept_name` varchar(100) DEFAULT '' COMMENT '部门名称',
  `attendance_date` date NOT NULL COMMENT '考勤日期',
  `check_in_time` datetime DEFAULT NULL COMMENT '签到时间',
  `check_out_time` datetime DEFAULT NULL COMMENT '签退时间',
  `location_result` varchar(200) DEFAULT '' COMMENT '签到位置(WGS84/GCJ02坐标)',
  `device_info` varchar(200) DEFAULT '' COMMENT '签到设备信息',
  `status` varchar(20) DEFAULT 'NORMAL' COMMENT '状态(NORMAL/LATE/EARLY/ABSENT/OVERTIME)',
  `source` varchar(20) DEFAULT 'MANUAL' COMMENT '数据来源(DINGTALK/WECHAT/MANUAL)',
  `callback_log_id` bigint DEFAULT NULL COMMENT '关联回调日志ID',
  `create_by` varchar(64) DEFAULT '',
  `create_time` datetime DEFAULT NULL,
  `remark` varchar(500) DEFAULT '',
  PRIMARY KEY (`record_id`),
