--
-- Table structure for table `iot_device_port`
--

DROP TABLE IF EXISTS `iot_device_port`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `iot_device_port` (
  `port_id` bigint NOT NULL AUTO_INCREMENT COMMENT '端口ID',
  `device_id` bigint NOT NULL COMMENT '所属设备ID',
  `port_name` varchar(100) COLLATE utf8mb4_general_ci NOT NULL COMMENT '端口名称',
  `port_type` varchar(20) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '端口类型',
  `port_status` varchar(20) COLLATE utf8mb4_general_ci DEFAULT 'DOWN' COMMENT '端口状态(UP/DOWN)',
  `connected_device_id` bigint DEFAULT NULL COMMENT '连接的对端设备ID',
  `connected_port_id` bigint DEFAULT NULL COMMENT '连接的对端端口ID',
  `remark` varchar(200) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '备注',
  `create_by` varchar(64) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `dept_id` bigint DEFAULT NULL COMMENT '所属组织ID',
  PRIMARY KEY (`port_id`),
  KEY `idx_device_id` (`device_id`),
  KEY `idx_connected_device` (`connected_device_id`),
  KEY `idx_iot_device_port_dept` (`dept_id`)
) ENGINE=InnoDB AUTO_INCREMENT=100 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='设备端口表';
/*!40101 SET character_set_client = @saved_cs_client */;

