--
-- Table structure for table `iot_device_status_log`
--

DROP TABLE IF EXISTS `iot_device_status_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `iot_device_status_log` (
  `log_id` bigint NOT NULL AUTO_INCREMENT COMMENT '日志ID',
  `device_id` bigint NOT NULL COMMENT '设备ID',
  `device_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '设备名称',
  `old_status` varchar(20) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '变更前状态',
  `new_status` varchar(20) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '变更后状态',
  `change_type` varchar(20) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '变更类型(OFFLINE:离线,ONLINE:上线)',
  `change_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '变更时间',
  `sms_sent` char(1) COLLATE utf8mb4_general_ci DEFAULT 'N' COMMENT '是否发送短信(Y/N)',
  `sms_recipient` varchar(50) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '短信接收人',
  `repair_id` bigint DEFAULT NULL COMMENT '关联维修工单ID',
  `create_by` varchar(64) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `remark` varchar(500) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '备注',
  `dept_id` bigint DEFAULT NULL COMMENT '所属组织ID',
  PRIMARY KEY (`log_id`),
  KEY `idx_device_id` (`device_id`),
  KEY `idx_change_time` (`change_time`),
  KEY `idx_change_type` (`change_type`),
  KEY `idx_iot_device_status_log_dept` (`dept_id`)
) ENGINE=InnoDB AUTO_INCREMENT=131 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='设备状态变更日志表';
/*!40101 SET character_set_client = @saved_cs_client */;

