--
-- Table structure for table `sys_sms_log`
--

DROP TABLE IF EXISTS `sys_sms_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sys_sms_log` (
  `sms_id` bigint NOT NULL AUTO_INCREMENT COMMENT '短信ID',
  `recipient` varchar(100) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '接收人姓名',
  `phone_number` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '手机号码',
  `content` varchar(500) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '短信内容',
  `send_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '发送时间',
  `send_result` varchar(20) COLLATE utf8mb4_general_ci DEFAULT 'SUCCESS' COMMENT '发送结果(SUCCESS/FAIL)',
  `biz_type` varchar(30) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '业务类型(DEVICE_OFFLINE/DEVICE_ONLINE/VISITOR_APPROVE/REPAIR)',
  `biz_id` bigint DEFAULT NULL COMMENT '关联业务ID',
  `create_by` varchar(64) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `remark` varchar(200) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '备注',
  `dept_id` bigint DEFAULT NULL COMMENT '所属组织ID',
  PRIMARY KEY (`sms_id`),
  KEY `idx_phone_number` (`phone_number`),
  KEY `idx_biz_type` (`biz_type`),
  KEY `idx_send_time` (`send_time`),
  KEY `idx_sys_sms_log_dept` (`dept_id`)
) ENGINE=InnoDB AUTO_INCREMENT=141 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='短信通知日志表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `sys_sms_log`
--

LOCK TABLES `sys_sms_log` WRITE;
/*!40000 ALTER TABLE `sys_sms_log` DISABLE KEYS */;
