--
-- Table structure for table `sys_user`
--

DROP TABLE IF EXISTS `sys_user`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sys_user` (
  `user_id` bigint NOT NULL AUTO_INCREMENT COMMENT '用户ID',
  `dept_id` bigint DEFAULT NULL COMMENT '部门ID',
  `external_dept_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '外部系统部门ID',
  `user_name` varchar(30) COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户账号',
  `job_number` varchar(50) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '工号(钉钉job_number)',
  `external_user_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '外部系统用户ID(钉钉userId/企业微信UserId)',
  `external_source` varchar(20) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '外部来源(DINGTALK/WECHAT)',
  `nick_name` varchar(30) COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户昵称',
  `alias_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '别名(企业微信alias)',
  `user_type` varchar(2) COLLATE utf8mb4_general_ci DEFAULT '00' COMMENT '用户类型（00系统用户）',
  `email` varchar(50) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '用户邮箱',
  `org_email` varchar(50) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '企业邮箱(钉钉org_email)',
  `position` varchar(100) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '职位/岗位名称',
  `work_place` varchar(100) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '工作地点(钉钉work_place)',
  `address` varchar(200) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '地址(企业微信address)',
  `hire_date` date DEFAULT NULL COMMENT '入职日期',
  `phonenumber` varchar(11) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '手机号码',
  `telephone` varchar(20) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '座机/分机号(钉钉tel/企微telephone)',
  `sex` char(1) COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '用户性别（0男 1女 2未知）',
  `avatar` varchar(100) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '头像地址',
  `photo` varchar(200) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '人员照片路径',
  `avatar_url` varchar(500) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '外部头像URL(钉钉/企业微信)',
  `password` varchar(100) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '密码',
  `status` char(1) COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '账号状态（0正常 1停用）',
  `del_flag` char(1) COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '删除标志（0代表存在 2代表删除）',
  `login_ip` varchar(128) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '最后登录IP',
  `login_date` datetime DEFAULT NULL COMMENT '最后登录时间',
  `pwd_update_date` datetime DEFAULT NULL COMMENT '密码最后更新时间',
  `create_by` varchar(64) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `ext_attr` text COLLATE utf8mb4_general_ci COMMENT '扩展属性JSON(其他字段)',
  PRIMARY KEY (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=109 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='用户信息表';
/*!40101 SET character_set_client = @saved_cs_client */;

