--
-- Table structure for table `visitor_appointment`
--

DROP TABLE IF EXISTS `visitor_appointment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `visitor_appointment` (
  `appointment_id` bigint NOT NULL AUTO_INCREMENT COMMENT '预约ID',
  `visitor_name` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '访客姓名',
  `visitor_phone` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '访客电话',
  `visitor_id_card` varchar(20) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '访客身份证号(预留人脸识别)',
  `visitor_company` varchar(100) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '访客单位',
  `visit_reason` varchar(200) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '访问事由',
  `host_name` varchar(50) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '被访人姓名',
  `host_dept` varchar(100) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '被访人部门',
  `host_phone` varchar(20) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '被访人电话',
  `visit_time` datetime DEFAULT NULL COMMENT '计划来访时间',
  `leave_time` datetime DEFAULT NULL COMMENT '实际离开时间',
  `status` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PENDING' COMMENT '状态(PENDING:待审批,APPROVED:已通过,REJECTED:已拒绝,CANCELLED:已取消,VISITING:来访中,COMPLETED:已完成)',
  `approver_id` bigint DEFAULT NULL COMMENT '审批人ID',
  `approve_time` datetime DEFAULT NULL COMMENT '审批时间',
  `approve_remark` varchar(500) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '审批备注',
  `sms_sent` char(1) COLLATE utf8mb4_general_ci DEFAULT 'N' COMMENT '是否发送短信(Y/N)',
  `sms_content` varchar(500) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '短信内容',
  `pass_code` varchar(20) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '通行码',
  `has_car` char(1) COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '是否开车(0=否 1=是)',
  `car_plate` varchar(20) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '车牌号',
  `has_goods` char(1) COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '是否携带物资(0=否 1=是)',
  `goods_desc` varchar(200) COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '携带物资说明',
